'use client';

import { useCallback } from 'react';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch, logClientError } from '@/shared/utils/observability/client-error-logger';
import { CHATBOT_SETTINGS_KEY, DEFAULT_CHATBOT_SETTINGS } from '@/shared/lib/ai/chatbot/constants';
import { parseChatbotSettingsPayload, type ChatbotSettingsDto as ChatbotSettingsPayload, type ChatbotSettingsResponse } from '@/shared/contracts/chatbot';
import type { SingleQuery, UpdateMutation } from '@/shared/contracts/ui/queries';
import { useSaveChatbotSettings } from './useChatbotMutations';

type SaveChatbotSettingsVariables = {
  key: string;
  settings: ChatbotSettingsPayload;
};

type ChatbotSettingsActions = {
  setModel: (val: string) => void;
  setWebSearchEnabled: (val: boolean) => void;
  setUseGlobalContext: (val: boolean) => void;
  setUseLocalContext: (val: boolean) => void;
  setLocalContextMode: (val: 'append' | 'override') => void;
  setSearchProvider: (val: string) => void;
  setPersonaId: (val: string | null) => void;
  setPlaywrightPersonaId: (val: string | null) => void;
  setAgentModeEnabled: (val: boolean) => void;
  setAgentBrowser: (val: string) => void;
  setAgentRunHeadless: (val: boolean) => void;
  setAgentIgnoreRobotsTxt: (val: boolean) => void;
  setAgentRequireHumanApproval: (val: boolean) => void;
  setAgentMaxSteps: (val: number) => void;
  setAgentMaxStepAttempts: (val: number) => void;
  setAgentMaxReplanCalls: (val: number) => void;
  setAgentReplanEverySteps: (val: number) => void;
  setAgentMaxSelfChecks: (val: number) => void;
  setAgentLoopGuardThreshold: (val: number) => void;
  setAgentLoopBackoffBaseMs: (val: number) => void;
  setAgentLoopBackoffMaxMs: (val: number) => void;
};

/**
 * Applies the parsed chatbot settings to the provided action handlers.
 */
function applySettingsToActions(res: ChatbotSettingsPayload, actions: ChatbotSettingsActions): void {
  if (typeof res.model === 'string' && res.model !== '') actions.setModel(res.model);
  actions.setWebSearchEnabled(Boolean(res.webSearchEnabled));
  actions.setUseGlobalContext(Boolean(res.useGlobalContext));
  actions.setUseLocalContext(Boolean(res.useLocalContext));
  actions.setLocalContextMode(res.localContextMode as 'append' | 'override');
  actions.setSearchProvider(res.searchProvider ?? DEFAULT_CHATBOT_SETTINGS.searchProvider ?? '');
  actions.setPersonaId(res.personaId ?? null);
  actions.setPlaywrightPersonaId(res.playwrightPersonaId ?? null);

  actions.setAgentModeEnabled(Boolean(res.agentModeEnabled));
  actions.setAgentBrowser(res.agentBrowser ?? DEFAULT_CHATBOT_SETTINGS.agentBrowser ?? 'chromium');
  actions.setAgentRunHeadless(Boolean(res.runHeadless));
  actions.setAgentIgnoreRobotsTxt(Boolean(res.ignoreRobotsTxt));
  actions.setAgentRequireHumanApproval(Boolean(res.requireHumanApproval));
  actions.setAgentMaxSteps(res.maxSteps ?? 10);
  actions.setAgentMaxStepAttempts(res.maxStepAttempts ?? 3);
  actions.setAgentMaxReplanCalls(res.maxReplanCalls ?? 3);
  actions.setAgentReplanEverySteps(res.replanEverySteps ?? 5);
  actions.setAgentMaxSelfChecks(res.maxSelfChecks ?? 3);
  actions.setAgentLoopGuardThreshold(res.loopGuardThreshold ?? 3);
  actions.setAgentLoopBackoffBaseMs(res.loopBackoffBaseMs ?? 1000);
  actions.setAgentLoopBackoffMaxMs(res.loopBackoffMaxMs ?? 5000);
}

/**
 * Hook for managing chatbot settings state handlers (loading/saving).
 */
export function useChatbotSettingsHandlers({
  settingsQuery,
  currentSettings,
  setSettingsSnapshot,
  setSettingsDirty,
  actions,
}: {
  settingsQuery: SingleQuery<ChatbotSettingsResponse>;
  currentSettings: ChatbotSettingsPayload;
  setSettingsSnapshot: React.Dispatch<React.SetStateAction<ChatbotSettingsPayload | null>>;
  setSettingsDirty: React.Dispatch<React.SetStateAction<boolean>>;
  actions: ChatbotSettingsActions;
}): {
  loadChatbotSettings: () => Promise<void>;
  saveChatbotSettings: () => Promise<void>;
  saveMutation: UpdateMutation<{ settings?: { settings?: ChatbotSettingsPayload } }, SaveChatbotSettingsVariables>;
} {
  const { toast } = useToast();
  const saveMutation = useSaveChatbotSettings();

  const loadChatbotSettings = useCallback((): Promise<void> => {
    if (settingsQuery.data?.settings?.settings === undefined) return Promise.resolve();

    try {
      const stored = parseChatbotSettingsPayload(settingsQuery.data.settings.settings);
      const res: ChatbotSettingsPayload = { ...DEFAULT_CHATBOT_SETTINGS, ...stored };

      applySettingsToActions(res, actions);

      setSettingsSnapshot(res);
      setSettingsDirty(false);
    } catch (err: unknown) {
      logClientCatch(err, { source: 'useChatbotSettingsState.loadChatbotSettings', key: CHATBOT_SETTINGS_KEY });
      toast(err instanceof Error ? err.message : 'Invalid chatbot settings payload.', { variant: 'error' });
    }
    return Promise.resolve();
  }, [settingsQuery.data, actions, setSettingsSnapshot, setSettingsDirty, toast]);

  const saveChatbotSettings = useCallback(async (): Promise<void> => {
    try {
      await saveMutation.mutateAsync({
        key: CHATBOT_SETTINGS_KEY,
        settings: currentSettings,
      });
      setSettingsDirty(false);
      setSettingsSnapshot(currentSettings);
      toast('Chatbot settings saved.', { variant: 'success' });
    } catch (err: unknown) {
      logClientError(err);
      toast(err instanceof Error ? err.message : 'Failed to save settings.', { variant: 'error' });
    }
  }, [currentSettings, saveMutation, setSettingsDirty, setSettingsSnapshot, toast]);

  return { loadChatbotSettings, saveChatbotSettings, saveMutation };
}

'use client';

import { useMemo } from 'react';
import type { ChatbotSettingsDto as ChatbotSettingsPayload } from '@/shared/contracts/chatbot';
import { DEFAULT_CHATBOT_SETTINGS } from '@/shared/lib/ai/chatbot/constants';

export function useChatbotSettingsMemo({
  model,
  personaId,
  webSearchEnabled,
  useGlobalContext,
  useLocalContext,
  localContextMode,
  searchProvider,
  playwrightPersonaId,
  agentModeEnabled,
  agentBrowser,
  agentRunHeadless,
  agentIgnoreRobotsTxt,
  agentRequireHumanApproval,
  agentMaxSteps,
  agentMaxStepAttempts,
  agentMaxReplanCalls,
  agentReplanEverySteps,
  agentMaxSelfChecks,
  agentLoopGuardThreshold,
  agentLoopBackoffBaseMs,
  agentLoopBackoffMaxMs,
}: {
  model: string;
  personaId: string | null;
  webSearchEnabled: boolean;
  useGlobalContext: boolean;
  useLocalContext: boolean;
  localContextMode: 'override' | 'append';
  searchProvider: string;
  playwrightPersonaId: string | null;
  agentModeEnabled: boolean;
  agentBrowser: string;
  agentRunHeadless: boolean;
  agentIgnoreRobotsTxt: boolean;
  agentRequireHumanApproval: boolean;
  agentMaxSteps: number;
  agentMaxStepAttempts: number;
  agentMaxReplanCalls: number;
  agentReplanEverySteps: number;
  agentMaxSelfChecks: number;
  agentLoopGuardThreshold: number;
  agentLoopBackoffBaseMs: number;
  agentLoopBackoffMaxMs: number;
}): ChatbotSettingsPayload {
  return useMemo<ChatbotSettingsPayload>(
    () => ({
      model,
      temperature: DEFAULT_CHATBOT_SETTINGS.temperature,
      maxTokens: DEFAULT_CHATBOT_SETTINGS.maxTokens,
      systemPrompt: DEFAULT_CHATBOT_SETTINGS.systemPrompt,
      personaId,
      enableMemory: DEFAULT_CHATBOT_SETTINGS.enableMemory,
      enableContext: DEFAULT_CHATBOT_SETTINGS.enableContext,
      webSearchEnabled,
      useGlobalContext,
      useLocalContext,
      localContextMode,
      searchProvider,
      playwrightPersonaId,
      agentModeEnabled,
      agentBrowser,
      runHeadless: agentRunHeadless,
      ignoreRobotsTxt: agentIgnoreRobotsTxt,
      requireHumanApproval: agentRequireHumanApproval,
      maxSteps: agentMaxSteps,
      maxStepAttempts: agentMaxStepAttempts,
      maxReplanCalls: agentMaxReplanCalls,
      replanEverySteps: agentReplanEverySteps,
      maxSelfChecks: agentMaxSelfChecks,
      loopGuardThreshold: agentLoopGuardThreshold,
      loopBackoffBaseMs: agentLoopBackoffBaseMs,
      loopBackoffMaxMs: agentLoopBackoffMaxMs,
    }),
    [
      model, personaId, webSearchEnabled, useGlobalContext, useLocalContext, localContextMode,
      searchProvider, playwrightPersonaId, agentModeEnabled, agentBrowser, agentRunHeadless,
      agentIgnoreRobotsTxt, agentRequireHumanApproval, agentMaxSteps, agentMaxStepAttempts,
      agentMaxReplanCalls, agentReplanEverySteps, agentMaxSelfChecks, agentLoopGuardThreshold,
      agentLoopBackoffBaseMs, agentLoopBackoffMaxMs,
    ]
  );
}

'use client';

import { PlusIcon, FileUp, Link as LinkIcon, MessageSquareQuote, Save } from 'lucide-react';
import React, { Suspense, useMemo, useCallback } from 'react';

import { AdminChatbotPageLayout } from '@/shared/ui/admin.public';
import { Button, useToast } from '@/shared/ui/primitives.public';
import { Tag, FileUploadTrigger, StatusToggle, SearchInput, Hint } from '@/shared/ui/forms-and-actions.public';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { EmptyState, LoadingState } from '@/shared/ui/navigation-and-layout.public';
import type { FileUploadHelpers } from '@/shared/contracts/ui/base';
import { cn } from '@/shared/utils/ui-utils';

import { ChatbotContextModal } from '../components/ChatbotContextModal';
import { useChatbotContextState } from '../hooks/useChatbotContextState';

import type { ContextItem } from '../hooks/useChatbotContextState';
import type { ColumnDef } from '@tanstack/react-table';

/**
 * Admin interface for managing chatbot context data.
 * Handles CRUD operations, file uploads, and filtering for context items
 * that inform the chatbot's knowledge base.
 */
function ChatbotContextPageInner(): React.JSX.Element {
  const { toast } = useToast();

  // Custom hook managing the business logic for context persistence, filtering, and modal state
  const {
    activeIds,
    tagQuery,
    setTagQuery,
    tagFilters,
    setTagFilters,
    uniqueTags,
    filteredContexts,
    isModalOpen,
    modalDraft,
    setModalDraft,
    tagDraft,
    setTagDraft,
    loading,
    saving,
    uploading,
    openCreateModal,
    openEditModal,
    closeModal,
    handleDeleteContext,
    handleSaveDraft,
    handlePdfUpload,
    handleSaveContexts,
    toggleActive,
  } = useChatbotContextState();

  const columns = useMemo<ColumnDef<ContextItem>[]>(
    () => [
      {
        accessorKey: 'title',
        header: 'Title',
        cell: ({ row }) => <span className='font-medium text-white'>{row.original.title}</span>,
      },
      {
        accessorKey: 'tags',
        header: 'Tags',
        cell: ({ row }) => (
          <div className='flex flex-wrap gap-1'>
            {(row.original.tags ?? []).length === 0 ? (
              <span className='text-xs text-gray-500'>None</span>
            ) : (
              (row.original.tags ?? []).map((tag: string) => <Tag key={tag} label={tag} />)
            )}
          </div>
        ),
      },
      {
        accessorKey: 'source',
        header: 'Source',
        cell: ({ row }) => (
          <span className='text-xs text-gray-400 capitalize'>
            {row.original.source ?? 'manual'}
          </span>
        ),
      },
      {
        id: 'active',
        header: 'Active',
        cell: ({ row }) => (
          <StatusToggle
            enabled={activeIds.includes(row.original.id)}
            onToggle={() => toggleActive(row.original.id, !activeIds.includes(row.original.id))}
          />
        ),
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => (
          <div className='flex justify-end gap-2'>
            <Button
              type='button'
              variant='outline'
              size='xs'
              onClick={() => openEditModal(row.original)}
            >
              Edit
            </Button>
            <Button
              type='button'
              variant='outline'
              size='xs'
              onClick={() => handleDeleteContext(row.original.id)}
              className='text-red-300 hover:text-red-200'
            >
              Delete
            </Button>
          </div>
        ),
      },
    ],
    [activeIds, toggleActive, openEditModal, handleDeleteContext]
  );

  const handleCopyLink = useCallback(() => {
    const params = new URLSearchParams();
    if (tagQuery.trim() !== '') {
      params.set('q', tagQuery.trim());
    }
    if (tagFilters.length > 0) {
      params.set('tags', tagFilters.join(','));
    }
    const url = `${window.location.origin}${window.location.pathname}?${params.toString()}`;
    void navigator.clipboard.writeText(url);
    toast('Filtered link copied', { variant: 'success' });
  }, [tagQuery, tagFilters, toast]);

  return (
    <AdminChatbotPageLayout
      title='Chatbot Context'
      current='Context'
      description='Define global instructions and reference materiał applied to every chat.'
      icon={<MessageSquareQuote className='size-4' />}
      headerActions={
        <>
          <Button type='button' variant='outline' size='sm' onClick={openCreateModal}>
            <PlusIcon className='mr-1 size-4' />
            Create Context
          </Button>
          <Button type='button' variant='outline' size='sm' onClick={handleCopyLink}>
            <LinkIcon className='mr-1 size-3.5' />
            Copy Filter Link
          </Button>
          <Button
            type='button'
            size='sm'
            onClick={() => {
              void handleSaveContexts();
            }}
            disabled={saving || loading}
          >
            <Save className='mr-1 size-3.5' />
            {saving ? 'Saving...' : 'Save Contexts'}
          </Button>
        </>
      }
    >
      <div className='space-y-6'>
        <StandardDataTablePanel
          filters={
            <div className='space-y-4'>
              <div className='flex flex-wrap items-center gap-3'>
                <SearchInput
                  placeholder='Search contexts or tags...'
                  value={tagQuery}
                  onChange={(event) => setTagQuery(event.target.value)}
                  onClear={() => setTagQuery('')}
                  className='h-9 w-full max-w-sm'
                  disabled={loading}
                  size='sm'
                />

                <FileUploadTrigger
                  accept='application/pdf'
                  disabled={loading || saving || uploading}
                  onFilesSelected={async (files: File[], helpers?: FileUploadHelpers) => {
                    const file = files[0];
                    if (!file) return;
                    await handlePdfUpload(file, helpers);
                  }}
                  asChild
                  preserveChildSemantics
                >
                  <Button variant='outline' size='sm' className='h-9 gap-2'>
                    <FileUp className={cn('size-4', uploading && 'animate-bounce')} />
                    {uploading ? 'Uploading PDF...' : 'Upload PDF'}
                  </Button>
                </FileUploadTrigger>
              </div>

              {uniqueTags.length > 0 && (
                <div className='flex flex-wrap items-center gap-2 pt-1 border-t border-white/5'>
                  <Hint uppercase variant='muted' className='mr-1 font-semibold'>
                    Quick Filter:
                  </Hint>
                  {uniqueTags.map((tag: string) => (
                    <Button
                      key={tag}
                      type='button'
                      size='xs'
                      variant={tagFilters.includes(tag) ? 'default' : 'outline'}
                      className='rounded-full h-6 px-3'
                      onClick={(): void => {
                        setTagFilters((prev) =>
                          prev.includes(tag) ? prev.filter((item) => item !== tag) : [...prev, tag]
                        );
                      }}
                    >
                      {tag}
                    </Button>
                  ))}
                  {tagFilters.length > 0 && (
                    <Button
                      type='button'
                      variant='ghost'
                      size='xs'
                      onClick={() => setTagFilters([])}
                      className='h-6 text-gray-400 hover:text-white'
                    >
                      Clear all
                    </Button>
                  )}
                </div>
              )}
            </div>
          }
          columns={columns}
          data={filteredContexts}
          isLoading={loading}
          emptyState={
            <EmptyState
              title='No contexts found'
              description={
                tagQuery || tagFilters.length > 0
                  ? 'Try adjusting your filters.'
                  : 'Global contexts provide instructions to the AI.'
              }
              icon={<MessageSquareQuote className='size-12 opacity-20' />}
            />
          }
        />

        <ChatbotContextModal
          isOpen={isModalOpen}
          onClose={closeModal}
          onSuccess={() => {}}
          item={modalDraft}
          modalDraft={modalDraft}
          setModalDraft={setModalDraft}
          tagDraft={tagDraft}
          setTagDraft={setTagDraft}
          isSaving={saving}
          onSave={handleSaveDraft}
        />
      </div>
    </AdminChatbotPageLayout>
  );
}

export default function ChatbotContextPage(): React.JSX.Element {
  return (
    <Suspense
      fallback={<LoadingState message='Mounting context environment...' className='py-12' />}
    >
      <ChatbotContextPageInner />
    </Suspense>
  );
}

'use client';

import { ChevronDown, ChevronUp } from 'lucide-react';
import { useMemo } from 'react';

import { AdminChatbotPageLayout } from '@/shared/ui/admin.public';
import { Button, Input, Card } from '@/shared/ui/primitives.public';
import { FormField, Tag, Hint } from '@/shared/ui/forms-and-actions.public';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { UI_GRID_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';

import { useChatbotMemoryState, type ExtendedMemoryItem } from '../hooks/useChatbotMemoryState';

import type { ColumnDef } from '@tanstack/react-table';

const formatDate = (value?: string | null): string => {
  if (!value) return '—';
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? '—' : date.toLocaleString();
};

export default function AgentMemoryPage(): React.JSX.Element {
  const {
    items,
    memoryKey,
    setMemoryKey,
    tag,
    setTag,
    query,
    setQuery,
    limit,
    setLimit,
    expanded,
    toggleExpanded,
    loading,
    isFetching,
    error,
    refetch,
  } = useChatbotMemoryState();

  const columns = useMemo<ColumnDef<ExtendedMemoryItem>[]>(
    () => [
      {
        id: 'expander',
        header: () => null,
        cell: ({ row }) => (
          <Button
            size='icon'
            variant='ghost'
            className='h-7 w-7'
            onClick={() => toggleExpanded(row.original.id)}
            aria-label={
              expanded[row.original.id] ? 'Collapse memory details' : 'Expand memory details'
            }
            aria-expanded={expanded[row.original.id]}
            title={expanded[row.original.id] ? 'Collapse memory details' : 'Expand memory details'}
          >
            {expanded[row.original.id] ? (
              <ChevronUp className='size-4' />
            ) : (
              <ChevronDown className='size-4' />
            )}
          </Button>
        ),
      },
      {
        accessorKey: 'value',
        header: 'Memory / Summary',
        cell: ({ row }) => (
          <div className='flex flex-col gap-1'>
            <span className='font-medium text-white'>
              {(row.original.metadata?.['summary'] as string) || row.original.value.slice(0, 100)}
            </span>
            <span className='text-[10px] text-gray-500 font-mono'>Key: {row.original.key}</span>
          </div>
        ),
      },
      {
        accessorKey: 'tags',
        header: 'Tags',
        cell: ({ row }) => (
          <div className='flex flex-wrap gap-1'>
            {(row.original.metadata?.['tags'] as string[])?.length ? (
              (row.original.metadata?.['tags'] as string[]).map((t) => <Tag key={t} label={t} />)
            ) : (
              <span className='text-xs text-gray-600'>None</span>
            )}
          </div>
        ),
      },
      {
        accessorKey: 'importance',
        header: 'Score',
        cell: ({ row }) => (
          <span className='text-xs font-medium text-gray-300'>
            {(row.original.metadata?.['importance'] as number) ?? '—'}
          </span>
        ),
      },
      {
        accessorKey: 'updatedAt',
        header: 'Last Seen',
        cell: ({ row }) => (
          <span className='text-xs text-gray-400'>{formatDate(row.original.updatedAt)}</span>
        ),
      },
    ],
    [expanded, toggleExpanded]
  );

  return (
    <AdminChatbotPageLayout
      title='Agent Long-Term Memory'
      current='Memory'
      description='Knowledge preserved by agents across conversations and runs.'
      headerActions={
        <Button variant='outline' size='xs' onClick={refetch} loading={isFetching}>
          Refresh
        </Button>
      }
    >
      <StandardDataTablePanel
        variant='flat'
        alerts={
          error ? (
            <p className='text-sm text-rose-400'>
              {error instanceof Error ? error.message : String(error)}
            </p>
          ) : null
        }
        filters={
          <div className={`${UI_GRID_RELAXED_CLASSNAME} md:grid-cols-4`}>
            <FormField label='Memory key'>
              <Input
                size='sm'
                value={memoryKey}
                onChange={(e) => setMemoryKey(e.target.value)}
                placeholder='run-id or key'
                className='h-8'
               aria-label='run-id or key' title='run-id or key'/>
            </FormField>
            <FormField label='Tag'>
              <Input
                size='sm'
                value={tag}
                onChange={(e) => setTag(e.target.value)}
                placeholder='tag name'
                className='h-8'
               aria-label='tag name' title='tag name'/>
            </FormField>
            <FormField label='Search content'>
              <Input
                size='sm'
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder='text search'
                className='h-8'
               aria-label='text search' title='text search'/>
            </FormField>
            <FormField label='Limit'>
              <Input
                size='sm'
                type='number'
                min={1}
                max={100}
                value={limit}
                onChange={(e) => setLimit(Number(e.target.value))}
                className='h-8'
               aria-label='Limit' title='Limit'/>
            </FormField>
          </div>
        }
        columns={columns}
        data={items}
        isLoading={loading}
        renderRowDetails={({ row }: { row: { original: ExtendedMemoryItem } }) => (
          <div className='p-4 space-y-4 bg-black/20'>
            <div className={`${UI_GRID_RELAXED_CLASSNAME} md:grid-cols-2`}>
              <div>
                <Hint size='xxs' uppercase className='mb-2'>
                  Full Content
                </Hint>
                <Card
                  variant='subtle-compact'
                  padding='sm'
                  className='border-border/60 bg-black/40 font-mono text-[11px] text-gray-300 whitespace-pre-wrap'
                >
                  {row.original.value}
                </Card>
              </div>
              <div>
                <Hint size='xxs' uppercase className='mb-2'>
                  Context Details
                </Hint>
                <Card
                  variant='subtle-compact'
                  padding='sm'
                  className='border-border/60 bg-black/40 space-y-2 text-xs text-gray-400'
                >
                  <div className='flex justify-between border-b border-white/5 pb-1'>
                    <span>Created</span>
                    <span className='text-gray-200'>{formatDate(row.original.createdAt)}</span>
                  </div>
                  <div className='flex justify-between border-b border-white/5 pb-1'>
                    <span>Accessed</span>
                    <span className='text-gray-200'>
                      {formatDate(row.original.metadata?.['lastAccessedAt'] as string)}
                    </span>
                  </div>
                  <div className='flex justify-between border-b border-white/5 pb-1'>
                    <span>Run ID</span>
                    <span className='font-mono text-gray-200'>
                      {(row.original.metadata?.['runId'] as string) || '—'}
                    </span>
                  </div>
                </Card>
                {row.original.metadata && (
                  <div className='mt-4'>
                    <Hint size='xxs' uppercase className='mb-2'>
                      Metadata
                    </Hint>
                    <Card
                      variant='subtle-compact'
                      padding='sm'
                      className='border-border/60 bg-black/40 font-mono text-[10px] text-gray-400 whitespace-pre-wrap'
                    >
                      {JSON.stringify(row.original.metadata, null, 2)}
                    </Card>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
        expanded={expanded}
      />
    </AdminChatbotPageLayout>
  );
}

'use client';

import { Eye, Trash2 } from 'lucide-react';
import Link from 'next/link';
import React, { useMemo } from 'react';

import type { ChatbotSessionListItem } from '@/shared/contracts/chatbot';
import { AdminChatbotPageLayout } from '@/shared/ui/admin.public';
import { Button, Input, Checkbox } from '@/shared/ui/primitives.public';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { EmptyState } from '@/shared/ui/navigation-and-layout.public';
import { SearchInput, FormActions } from '@/shared/ui/forms-and-actions.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';

import { useChatbotSessionsState } from '../hooks/useChatbotSessionsState';

import type { ColumnDef } from '@tanstack/react-table';

export default function ChatbotSessionsPage(): React.JSX.Element {
  const {
    filteredSessions,
    searchQuery,
    setSearchQuery,
    editingId,
