                  size='sm'
                  value={draftTitle}
                  onChange={(e) => setDraftTitle(e.target.value)}
                  className='h-7 max-w-xs text-xs'
                  ref={(node) => {
                    node?.focus();
                  }}
                  aria-label='Session title'
                  title='Session title'
                />
