source:
/**
 * Chatbot Session Repository
 * 
 * Provides database operations for managing AI Chatbot sessions and message history.
 * Handles the persistence of chat sessions, including message threads, metadata,
 * user-specific settings, and persona-based routing.
 * 
 * Features:
 * - Session Management: Supports CRUD operations for chat threads and historical records.
 * - Normalization Pipeline: Enforces data integrity by normalizing dates, arrays, 
 *   and records during read/write transitions (MongoDB Document <-> DTO).
 * - Indexed Performance: Manages indices on critical fields (e.g., `updatedAt`, `personaId`)
 *   to ensure efficient session retrieval.
 * - Atomic Updates: Implements atomic message appending to ensure thread consistency.
 * 
 * Usage:
 * Use this service to interact with the database layer for all chatbot session
 * persistent operations. It abstracts raw MongoDB documents into defined DTOs.
 */

import 'server-only';

import { randomUUID } from 'crypto';

import type {
  ChatbotSessionDto as ChatSession,
  CreateChatSessionDto as CreateSessionInput,
  UpdateChatSessionDto as UpdateSessionInput,
  ChatMessageDto as ChatMessage,
  ChatbotSettingsPayload,
} from '@/shared/contracts/chatbot';
import { parseChatbotSettingsPayload } from '@/shared/contracts/chatbot';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

/** Name of the collection storing chatbot session data. */
const COLLECTION_NAME = 'chatbot_sessions';

/** MongoDB document representation of a chat message. */
type ChatMessageDocument = {
  id: string;
  sessionId: string;
  role: ChatMessage['role'];
  content: string;
  createdAt: Date;
  model?: string | null;
  images?: string[];
  toolCalls?: Array<Record<string, unknown>>;
  toolResults?: Array<Record<string, unknown>>;
  metadata?: Record<string, unknown> | null;
};

/** MongoDB document representation of a chat session. */
type ChatSessionDocument = {
  _id: string;
  id: string;
  title: string | null;
  userId?: string | null;
  personaId?: string | null;
  settings?: Record<string, unknown> | null;
  lastMessageAt?: Date | null;
  messageCount?: number;
  isActive?: boolean;
  tags?: string[];
  metadata?: Record<string, unknown> | null;
  messages: ChatMessageDocument[];
  createdAt: Date;
  updatedAt: Date;
};

/** Utility to verify if a value is a plain record object. */
const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

/** Normalizes arbitrary values into plain record objects. */
const normalizeRecord = (value: unknown): Record<string, unknown> | undefined => {
  if (!isRecord(value)) return undefined;
  const serialized = JSON.stringify(value, (_key: string, entry: unknown) =>
    typeof entry === 'bigint' ? entry.toString() : entry
  );
  if (!serialized) return undefined;
  const parsed = JSON.parse(serialized) as unknown;
  return isRecord(parsed) ? parsed : undefined;
};

/** Normalizes arrays by filtering out non-string/empty entries. */
const normalizeStringArray = (value: unknown): string[] | undefined => {
  if (!Array.isArray(value)) return undefined;
  const normalized = value
    .map((entry: unknown) => (typeof entry === 'string' ? entry.trim() : ''))
    .filter((entry: string): boolean => entry.length > 0);
  return normalized;
};

/** Normalizes arrays by recursively processing record elements. */
const normalizeObjectArray = (value: unknown): Array<Record<string, unknown>> | undefined => {
  if (!Array.isArray(value)) return undefined;
  const normalized = value
    .map((entry: unknown) => normalizeRecord(entry))
    .filter((entry): entry is Record<string, unknown> => Boolean(entry));
  return normalized;
};

/** Normalizes date inputs to valid Date instances. */
const normalizeDate = (value: unknown, fallback: Date = new Date()): Date => {
  if (value instanceof Date && !Number.isNaN(value.getTime())) {
    return value;
  }
  if (typeof value === 'string' || typeof value === 'number') {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) {
      return parsed;
    }
  }
  return fallback;
};

/** Normalizes persona identifiers to string or null. */
const normalizePersonaId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

/** Resolves the persona ID from the provided input options or existing settings. */
const resolvePersonaId = (input: {
  personaId?: unknown;
  settings?: ChatbotSettingsPayload | Record<string, unknown> | null;
}): string | null => {
  const settingsPersonaId =
    isRecord(input.settings) ? normalizePersonaId(input.settings['personaId']) : null;
  return settingsPersonaId ?? normalizePersonaId(input.personaId) ?? null;
};

/** Parses and normalizes chatbot settings payload from stored document data. */
const normalizeStoredSettings = (
  value: unknown
): ChatbotSettingsPayload | undefined => {
  const record = normalizeRecord(value);
  if (!record) return undefined;
  try {
    return parseChatbotSettingsPayload(record);
  } catch (error) {
    void ErrorSystem.captureException(error);
    return undefined;
  }
};

/** Converts a DB message document to the application-level DTO. */
const toChatMessage = (message: ChatMessageDocument): ChatMessage => ({
  id: message.id,
  sessionId: message.sessionId,
  role: message.role,
  content: message.content,
  timestamp: message.createdAt.toISOString(),
  ...(message.model ? { model: message.model } : {}),
  ...(Array.isArray(message.images) && message.images.length > 0 ? { images: message.images } : {}),
  ...(Array.isArray(message.toolCalls) && message.toolCalls.length > 0
    ? { toolCalls: message.toolCalls }
    : {}),
  ...(Array.isArray(message.toolResults) && message.toolResults.length > 0
    ? { toolResults: message.toolResults }
    : {}),
  ...(isRecord(message.metadata) ? { metadata: message.metadata } : {}),
});

/** Converts a DB session document to the application-level DTO. */
const toChatSession = (session: ChatSessionDocument): ChatSession => {
  const messages = [...(Array.isArray(session.messages) ? session.messages : [])]
    .sort((left, right) => left.createdAt.getTime() - right.createdAt.getTime())
    .map(toChatMessage);
  const settings = normalizeStoredSettings(session.settings);
  const lastMessageAt =
    session.lastMessageAt?.toISOString() ??
    messages[messages.length - 1]?.timestamp ??
    session.updatedAt.toISOString();

  return {
    id: session.id ?? session._id,
    title: session.title ?? null,
    userId: session.userId ?? null,
    personaId: session.personaId ?? null,
    ...(settings ? { settings } : {}),
    messages,
    messageCount: typeof session.messageCount === 'number' ? session.messageCount : messages.length,
    lastMessageAt,
    isActive: session.isActive ?? true,
    ...(Array.isArray(session.tags) && session.tags.length > 0 ? { tags: session.tags } : {}),
    ...(isRecord(session.metadata) ? { metadata: session.metadata } : {}),
    createdAt: session.createdAt.toISOString(),
    updatedAt: session.updatedAt.toISOString(),
  };
};

/** Converts application-level message DTOs to DB-compatible document formats. */
const toMessageDocument = (
  sessionId: string,
  message: Partial<ChatMessage> & { role: ChatMessage['role']; content: string }
): ChatMessageDocument => {
  const createdAt = normalizeDate(message.timestamp);
  return {
    id: typeof message.id === 'string' && message.id.trim().length > 0 ? message.id : randomUUID(),
    sessionId,
    role: message.role,
    content: message.content,
    createdAt,
    ...(typeof message.model === 'string' && message.model.trim().length > 0
      ? { model: message.model }
      : {}),
    ...(Array.isArray(message.images) ? { images: normalizeStringArray(message.images) ?? [] } : {}),
    ...(Array.isArray(message.toolCalls)
      ? { toolCalls: normalizeObjectArray(message.toolCalls) ?? [] }
      : {}),
    ...(Array.isArray(message.toolResults)
      ? { toolResults: normalizeObjectArray(message.toolResults) ?? [] }
      : {}),
    ...(normalizeRecord(message.metadata) ? { metadata: normalizeRecord(message.metadata)! } : {}),
  };
};

/** Batch-converts message DTOs to DB document format. */
const toMessageDocuments = (sessionId: string, messages: ChatMessage[] | undefined): ChatMessageDocument[] =>
  Array.isArray(messages)
    ? messages.map((message: ChatMessage) => toMessageDocument(sessionId, message))
    : [];

let indexesReady = false;
let indexesPromise: Promise<void> | null = null;

/** Ensures necessary DB indices are present for efficient session queries. */
const ensureSessionIndexes = async (): Promise<void> => {
  if (indexesReady) return;
  if (!indexesPromise) {
    indexesPromise = (async (): Promise<void> => {
      const db = await getMongoDb();
      const collection = db.collection<ChatSessionDocument>(COLLECTION_NAME);
      await Promise.all([
        collection.createIndex({ updatedAt: -1 }),
        collection.createIndex({ personaId: 1, title: 1 }),
      ]);
      indexesReady = true;
    })().catch((error: unknown) => {
      indexesPromise = null;
      throw error;
    });
  }
  await indexesPromise;
};

/** Retrieves the chatbot session collection, ensuring indices are established. */
const getSessionsCollection = async () => {
  await ensureSessionIndexes();
  const db = await getMongoDb();
  return db.collection<ChatSessionDocument>(COLLECTION_NAME);
};

export interface ChatbotSessionRepository {
  findAll(): Promise<ChatSession[]>;
  findById(id: string): Promise<ChatSession | null>;
  findSessionIdByPersonaAndTitle(title: string, personaId: string): Promise<string | null>;
  create(input: CreateSessionInput): Promise<ChatSession>;
  update(id: string, input: UpdateSessionInput): Promise<ChatSession | null>;
  delete(id: string): Promise<boolean>;
  deleteMany(ids: string[]): Promise<number>;
  addMessage(
    id: string,
    message: Partial<ChatMessage> & { role: ChatMessage['role']; content: string }
  ): Promise<ChatSession | null>;
}

export const chatbotSessionRepository: ChatbotSessionRepository = {
  async findAll(): Promise<ChatSession[]> {
    const collection = await getSessionsCollection();
    const sessions = await collection.find({}).sort({ updatedAt: -1 }).toArray();
    return sessions.map(toChatSession);
  },

  async findById(id: string): Promise<ChatSession | null> {
    const collection = await getSessionsCollection();
    const session = await collection.findOne({ $or: [{ _id: id }, { id }] });
    return session ? toChatSession(session) : null;
  },

  async findSessionIdByPersonaAndTitle(title: string, personaId: string): Promise<string | null> {
    const collection = await getSessionsCollection();
    const session = await collection.findOne(
      { personaId, title },
      { projection: { _id: 1, id: 1 } }
    );
    if (!session) return null;
    return String(session.id ?? session._id);
  },

  async create(input: CreateSessionInput): Promise<ChatSession> {
    const collection = await getSessionsCollection();
    const sessionId = randomUUID();
    const createdAt = new Date();
    const messages = toMessageDocuments(sessionId, input.messages);
    const lastMessageAt = messages[messages.length - 1]?.createdAt ?? null;
    const settings = normalizeRecord(input.settings) ?? null;
    const document: ChatSessionDocument = {
      _id: sessionId,
      id: sessionId,
      title: input.title ?? null,
      userId: input.userId ?? null,
      personaId: resolvePersonaId({ personaId: input.personaId, settings: input.settings }),
      settings,
      lastMessageAt,
      messageCount: messages.length,
      isActive: input.isActive ?? true,
      tags: normalizeStringArray(input.tags) ?? [],
      metadata: normalizeRecord(input.metadata) ?? null,
      messages,
      createdAt,
      updatedAt: lastMessageAt ?? createdAt,
    };
    await collection.insertOne(document);
    return toChatSession(document);
  },

  async update(id: string, input: UpdateSessionInput): Promise<ChatSession | null> {
    const collection = await getSessionsCollection();
    const existing = await collection.findOne({ $or: [{ _id: id }, { id }] });
    if (!existing) return null;

    const now = new Date();
    const nextMessages =
      input.messages !== undefined
        ? toMessageDocuments(existing.id ?? existing._id, input.messages)
        : undefined;
    const nextLastMessageAt =
      nextMessages !== undefined
        ? (nextMessages[nextMessages.length - 1]?.createdAt ?? null)
        : (existing.lastMessageAt ?? null);
    const nextSettings =
      input.settings !== undefined ? (normalizeRecord(input.settings) ?? null) : existing.settings ?? null;
    const updateDoc: Record<string, unknown> = {
      updatedAt: now,
      ...(input.title !== undefined ? { title: input.title ?? null } : {}),
      ...(input.userId !== undefined ? { userId: input.userId ?? null } : {}),
      ...(input.isActive !== undefined ? { isActive: input.isActive } : {}),
      ...(input.tags !== undefined ? { tags: normalizeStringArray(input.tags) ?? [] } : {}),
      ...(input.metadata !== undefined ? { metadata: normalizeRecord(input.metadata) ?? null } : {}),
      ...(input.settings !== undefined ? { settings: nextSettings } : {}),
      ...(nextMessages !== undefined
        ? { messages: nextMessages, messageCount: nextMessages.length, lastMessageAt: nextLastMessageAt }
        : {}),
      personaId: resolvePersonaId({
        personaId: input.personaId ?? existing.personaId,
        settings: input.settings !== undefined ? input.settings : existing.settings ?? null,
      }),
    };

    await collection.updateOne({ $or: [{ _id: id }, { id }] }, { $set: updateDoc });
    return this.findById(id);
  },

  async delete(id: string): Promise<boolean> {
    const collection = await getSessionsCollection();
    const result = await collection.deleteOne({ $or: [{ _id: id }, { id }] });
    return (result.deletedCount ?? 0) > 0;
  },

  async deleteMany(ids: string[]): Promise<number> {
    if (ids.length === 0) return 0;
    const collection = await getSessionsCollection();
    const result = await collection.deleteMany({
      $or: [{ _id: { $in: ids } }, { id: { $in: ids } }],
    });
    return result.deletedCount ?? 0;
  },

  async addMessage(
    id: string,
    message: Partial<ChatMessage> & { role: ChatMessage['role']; content: string }
  ): Promise<ChatSession | null> {
    const collection = await getSessionsCollection();
    const messageDocument = toMessageDocument(id, message);
    const result = await collection.updateOne(
      { $or: [{ _id: id }, { id }] },
      {
        $push: { messages: messageDocument },
        $set: { updatedAt: messageDocument.createdAt, lastMessageAt: messageDocument.createdAt },
        $inc: { messageCount: 1 },
      }
    );
    if ((result.matchedCount ?? 0) === 0) return null;
    return this.findById(id);
  },
};

import {
  type AgentAuditLogDto as AgentAuditLog,
  type AgentBrowserLogDto as AgentBrowserLog,
  type ChatbotTimelineEntryDto as TimelineEntry,
} from '@/shared/contracts/chatbot';
import type { IdLabelOptionDto } from '@/shared/contracts/base';

const getMetadataRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;

export const buildAgentResultMessage = (
  audits: AgentAuditLog[],
  status: string | null
): string | null => {
  const taskType: unknown = audits
    .map((audit: AgentAuditLog): unknown => audit.metadata)
    .find(
      (metadata: unknown): boolean =>
        Boolean(metadata) &&
        typeof (metadata as { plannerMeta?: { taskType?: string } }).plannerMeta?.taskType ===
          'string'
    );
  const resolvedTaskType: string | null =
    (taskType as { plannerMeta?: { taskType?: string } })?.plannerMeta?.taskType ?? null;
  const extractionAudit: AgentAuditLog | undefined = audits.find(
    (audit: AgentAuditLog): boolean => {
      const metadata = getMetadataRecord(audit.metadata);
      return Array.isArray(metadata?.['items']) || Array.isArray(metadata?.['names']);
    }
  );
  if (extractionAudit) {
    const metadata = getMetadataRecord(extractionAudit.metadata);
    const extractionItems: unknown[] = Array.isArray(metadata?.['items'])
      ? (metadata['items'] as unknown[])
      : Array.isArray(metadata?.['names'])
        ? (metadata['names'] as unknown[])
        : [];
    const items: string[] = extractionItems
      .filter((name: unknown): name is string => typeof name === 'string')
      .map((name: string): string => name.trim())
      .filter(Boolean);
    if (items.length > 0) {
      const url: string | null =
        typeof metadata?.['url'] === 'string'
          ? metadata['url']
          : null;
      const extractionType: string | null =
        typeof metadata?.['extractionType'] === 'string'
          ? metadata['extractionType']
          : null;
      const label: string =
        extractionType === 'emails'
          ? 'Extracted emails'
          : extractionType === 'product_names'
            ? 'Extracted product names'
            : 'Extracted information';
      const intro: string = url ? `${label} found on ${url}:` : `${label}:`;
      return `${intro}\n${items.map((name: string): string => `- ${name}`).join('\n')}`;
    }
  }
  const emptyAudit: AgentAuditLog | undefined = audits.find(
    (audit: AgentAuditLog): boolean => audit.message === 'No product names extracted.'
  );
  if (emptyAudit) {
    const metadata = getMetadataRecord(emptyAudit.metadata);
    const url: string | null =
      typeof metadata?.['url'] === 'string' ? metadata['url'] : null;
    return `No information extracted${url ? ` from ${url}` : ''}.`;
  }
  if (status === 'completed') {
    if (resolvedTaskType === 'extract_info') {
      return 'No information extracted.';
    }
    if (resolvedTaskType === 'web_task') {
      return 'Agent run completed. Actions executed in agent mode.';
    }
    return 'Agent run completed. No extractable results.';
  }
  if (status === 'failed') {
    return 'Agent run failed. Check the agent run details for errors.';
  }
  if (status === 'waiting_human') {
    return 'Agent run needs human input to continue.';
  }
  return null;
};

export const buildAgentResumeSummaryMessage = (audits: AgentAuditLog[]): string | null => {
  const resumeAudit: AgentAuditLog | undefined = audits.find(
    (audit: AgentAuditLog): boolean => audit.message === 'Resume summary prepared.'
  );
  const autoResumeAudit: AgentAuditLog | undefined = audits.find(
    (audit: AgentAuditLog): boolean => audit.message === 'Auto-resume queued for stuck run.'
  );
  if (!resumeAudit) {
    if (!autoResumeAudit) return null;
    const timestamp: string | null = autoResumeAudit.createdAt
      ? new Date(autoResumeAudit.createdAt).toLocaleString()
      : null;
    return `Auto-resume queued for stuck run${timestamp ? ` (${timestamp})` : ''}.`;
  }
  const metadata = getMetadataRecord(resumeAudit.metadata);
  const summary: string =
    typeof metadata?.['summary'] === 'string'
      ? metadata['summary'].trim()
      : '';
  if (!summary) return null;
  return `Resume summary:
${summary}`;
};

export const buildToolTimeline = (
  logs: AgentBrowserLog[],
  audits: AgentAuditLog[]
): TimelineEntry[] => {
  const auditEntries: TimelineEntry[] = audits
    .filter((audit: AgentAuditLog): boolean =>
      /tool|playwright|snapshot|selector|extraction|login|search|navigation/i.test(audit.message)
    )
    .map(
      (audit: AgentAuditLog): TimelineEntry => ({
        id: `audit-${audit.id}`,
        type: 'log' as const,
        level: audit.level,
        content: audit.message,
        timestamp: audit.createdAt || new Date().toISOString(),
        metadata: audit.metadata,
      })
    );
  const logEntries: TimelineEntry[] = logs.map(
    (log: AgentBrowserLog): TimelineEntry => ({
      id: `browser-${log.id}`,
      type: 'log' as const,
      level: log.level,
      content: log.message,
      timestamp: log.createdAt || new Date().toISOString(),
      metadata: log.metadata,
    })
  );
  return [...auditEntries, ...logEntries].sort(
    (a: TimelineEntry, b: TimelineEntry): number =>
      new Date(a.timestamp || 0).getTime() - new Date(b.timestamp || 0).getTime()
  );
};

export const getSelfCheckAudits = (audits: AgentAuditLog[]): AgentAuditLog[] =>
  audits.filter((audit: AgentAuditLog): boolean => audit.message === 'Self-check completed.');

type AdaptiveTrigger = IdLabelOptionDto & {
  createdAt: string;
  reason: string | null;
};

export const getLatestAdaptiveTrigger = (
  audits: AgentAuditLog[]
): AdaptiveTrigger | null => {
  const candidates: Array<AdaptiveTrigger> = audits
    .map(
      (audit: AgentAuditLog): AdaptiveTrigger | null => {
        const metadata: {
          type?: string;
          reason?: string | null;
        } | null = audit.metadata as {
          type?: string;
          reason?: string | null;
        } | null;
        const type: string | undefined = metadata?.['type'];
        if (type !== 'plan-replan' && type !== 'plan-adapt' && type !== 'self-check-replan') {
          return null;
        }
        const label: string =
          type === 'plan-adapt'
            ? 'mid-run adaptation'
            : type === 'self-check-replan'
              ? 'self-check replan'
              : 'adaptive replan';
        return {
          id: audit.id,
          createdAt: audit.createdAt || new Date().toISOString(),
          reason: typeof metadata?.['reason'] === 'string' ? metadata['reason'] : null,
          label,
        };
      }
    )
    .filter((item: AdaptiveTrigger | null): item is AdaptiveTrigger => Boolean(item));
  if (candidates.length === 0) return null;
  return candidates.reduce(
    (
      latest: AdaptiveTrigger,
      current: AdaptiveTrigger
    ): AdaptiveTrigger => {
      const latestTime: number = Date.parse(latest.createdAt);
      const currentTime: number = Date.parse(current.createdAt);
      return currentTime > latestTime ? current : latest;
    },
    candidates[0]!
  );
};

export const getLatestAuditByType = (
  audits: AgentAuditLog[],
  type: string
): AgentAuditLog | null => {
  const filtered: AgentAuditLog[] = audits.filter(
    (audit: AgentAuditLog): boolean => getMetadataRecord(audit.metadata)?.['type'] === type
  );
  return filtered.length ? filtered[filtered.length - 1]! : null;
};

export const resolveIgnoreRobots = (planState?: Record<string, unknown> | null): boolean => {
  if (!planState || typeof planState !== 'object') return false;
  const prefs: { ignoreRobotsTxt?: boolean } | undefined = (
    planState as { preferences?: { ignoreRobotsTxt?: boolean } }
  ).preferences;
  return Boolean(prefs?.ignoreRobotsTxt);
};

export const resolveApprovalStepId = (
  planState?: Record<string, unknown> | null
): string | null => {
  if (!planState || typeof planState !== 'object') return null;
  const approval: string | null | undefined = (
    planState as { approvalRequestedStepId?: string | null }
  ).approvalRequestedStepId;
  return typeof approval === 'string' ? approval : null;
};

export const formatDependencies = (dependsOn?: string[] | null): string | null => {
  if (!dependsOn || dependsOn.length === 0) return null;
  const readable: string[] = dependsOn.map((item: string): string => {
    const match: RegExpMatchArray | null = item.match(/^step-(\d+)$/);
    if (!match) return item;
    const index: number = Number(match[1]);
    if (!Number.isFinite(index)) return item;
    return `#${index + 1}`;
  });
  return readable.join(', ');
};

export const getAuditList = (value: unknown): string[] =>
  Array.isArray(value)
    ? value
      .filter((item: unknown): item is string => typeof item === 'string')
      .map((item: string): string => item.trim())
      .filter(Boolean)
    : [];

export const formatAdaptiveReason = (reason?: string | null): string => {
  if (!reason) return 'unspecified';
  const trimmed: string = reason.trim();
  if (!trimmed) return 'unspecified';
  if (trimmed.includes(' ')) return trimmed;
  return trimmed.replace(/-/g, ' ');
};

export const isAbortError = (error: unknown): boolean =>
  (error instanceof Error && error.name === 'AbortError') ||
  (typeof error === 'object' &&
    error !== null &&
    (error as { name?: string }).name === 'AbortError');

import {
  type ModelProfileDto as ModelProfile,
  type ModelTaskRuleDto as ModelTaskRule,
  type ExtendedModelProfile,
} from '@/shared/contracts/chatbot';

export const parseModelSize = (normalized: string): number | null => {
  const mixMatch: RegExpMatchArray | null = normalized.match(/(\d+)\s*x\s*(\d+(?:\.\d+)?)b/);
  if (mixMatch) {
    return Number(mixMatch[1]) * Number(mixMatch[2]);
  }
  const sizeMatch: RegExpMatchArray | null = normalized.match(/(\d+(?:\.\d+)?)b/);
  if (sizeMatch) return Number(sizeMatch[1]);
  if (normalized.includes('xxl')) return 34;
  if (normalized.includes('xlarge') || normalized.includes('xl')) return 13;
  if (normalized.includes('large')) return 13;
  if (normalized.includes('medium')) return 7;
  if (normalized.includes('small') || normalized.includes('mini')) return 3;
  if (normalized.includes('tiny')) return 1.5;
  return null;
};

export const buildModelProfile = (name: string): ExtendedModelProfile => {
  const normalized: string = name.toLowerCase();
  const isEmbedding: boolean = [
    'embed',
    'embedding',
    'text-embedding',
    'nomic-embed',
    'bge',
    'e5',
    'gte',
  ].some((tag: string): boolean => normalized.includes(tag));
  const isRerank: boolean = ['rerank', 'reranker', 'cross-encoder'].some((tag: string): boolean =>
    normalized.includes(tag)
  );
  const isVision: boolean = [
    'vision',
    'llava',
    'bakllava',
    'minicpm',
    'moondream',
    'qwen-vl',
    'cogvlm',
  ].some((tag: string): boolean => normalized.includes(tag));
  const isCode: boolean = ['code', 'coder', 'codestral', 'codeqwen', 'starcoder', 'codegen'].some(
    (tag: string): boolean => normalized.includes(tag)
  );
  const isInstruct: boolean = ['instruct', 'assistant'].some((tag: string): boolean =>
    normalized.includes(tag)
  );
  const isChat: boolean = normalized.includes('chat');
  const isReasoning: boolean =
    normalized.includes('reasoner') || /(^|[^a-z0-9])r1($|[^a-z0-9])/.test(normalized);

  return {
    id: name,
    name,
    provider: 'ollama',
    capabilities: [],
    contextWindow: 4096,
    maxOutputTokens: 2048,
    normalized,
    size: parseModelSize(normalized),
    isEmbedding,
    isRerank,
    isVision,
    isCode,
    isInstruct,
    isChat,
    isReasoning,
  };
};

export const buildModelProfileFromObject = (profile: ModelProfile): ExtendedModelProfile => {
  const base = buildModelProfile(profile.name);
  return {
    ...base,
    ...profile,
    isEmbedding: profile.isEmbedding || base.isEmbedding,
  };
};

export const scoreModelForTask = (profile: ExtendedModelProfile, rule: ModelTaskRule): number => {
  if (profile.isEmbedding || profile.isRerank) return Number.NEGATIVE_INFINITY;
  const size: number = profile.size ?? 7;
  let score: number = 0;
  if (profile.isInstruct || profile.isChat) score += 1;
  if (profile.isReasoning) score += rule.preferReasoning ? 1.2 : 0.3;
  if (profile.isVision) score -= 1.5;
  if (profile.isCode) score -= 0.4;
  if (rule.preferLarge) score += size * 0.35;
  if (rule.preferSmall) score += (10 - size) * 0.25;
  if (rule.targetSize) score -= Math.abs(size - rule.targetSize) * 0.7;
  if (rule.minSize && size < rule.minSize) {
    score -= (rule.minSize - size) * 0.9;
  }
  if (rule.maxSize && size > rule.maxSize) {
    score -= (size - rule.maxSize) * 0.4;
  }
  return score;
};

export const pickBestModel = (
  profiles: readonly ModelProfile[],
  rule: ModelTaskRule
): string | null => {
  let bestName: string | null = null;
  let bestScore: number = Number.NEGATIVE_INFINITY;
  let bestSize: number = -1;

  for (const rawProfile of profiles) {
    const profile = buildModelProfileFromObject(rawProfile);
    const score: number = scoreModelForTask(profile, rule);
    if (!Number.isFinite(score)) continue;

    const size: number = profile.size ?? 0;

    if (bestName === null || score > bestScore || (score === bestScore && size > bestSize)) {
      bestName = profile.name;
      bestScore = score;
      bestSize = size;
    }
  }

  return bestName;
};

import { type ChatMessageDto as ChatMessage } from '@/shared/contracts/chatbot';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export const safeLocalStorageGet = (key: string): string | null => {
  try {
    return window.localStorage.getItem(key);
  } catch (error) {
    logClientError(error);
    return null;
  }
};

export const safeLocalStorageSet = (key: string, value: string): void => {
  try {
    window.localStorage.setItem(key, value);
  } catch (error) {
    logClientError(error);

    // ignore storage failures
  }
};

export const safeLocalStorageRemove = (key: string): void => {
  try {
    window.localStorage.removeItem(key);
  } catch (error) {
    logClientError(error);

    // ignore storage failures
  }
};

export const readCachedMessages = (sessionId: string): ChatMessage[] => {
  try {
    const raw: string | null = window.localStorage.getItem(`chatbotSessionCache:${sessionId}`);
    if (!raw) return [];
    const parsed: unknown = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return (parsed as unknown[]).filter(
      (message: unknown): message is ChatMessage =>
        message != null &&
        typeof message === 'object' &&
        'content' in message &&
        typeof (message as { content: unknown }).content === 'string'
    );
  } catch (error) {
    logClientError(error);
    return [];
  }
};

export const writeCachedMessages = (sessionId: string, messages: ChatMessage[]): void => {
  try {
    const safeMessages: ChatMessage[] = messages.filter(
      (message: ChatMessage): boolean =>
        message.role !== 'system' && message.content.trim().length > 0
    );
    window.localStorage.setItem(`chatbotSessionCache:${sessionId}`, JSON.stringify(safeMessages));
  } catch (error) {
    logClientError(error);

    // ignore cache failures
  }
};

/**
 * Chatbot Job Processor
 * 
 * Background worker responsible for executing chatbot inference jobs.
 * This service mediates between the job queue, the Brain model runtime,
 * and the session repository to produce and store assistant responses.
 * 
 * Features:
 * - Model Execution: Integrates with `runChatbotModel` to process AI inferences.
 * - Context Enrichment: Merges base system prompts with dynamic context-registry data.
 * - Persistence: Automatically commits assistant responses to the session thread 
 *   and updates job status upon completion.
 * - Robust Error Handling: Ensures failure states are tracked via the chatbot repository.
 * 
 * Usage:
 * Invoked by the job worker infrastructure.
 */

import { buildChatbotContextRegistrySystemPrompt } from '@/features/ai/chatbot/context-registry/system-prompt';
import { chatbotJobRepository } from '@/features/ai/chatbot/services/chatbot-job-repository';
import { chatbotSessionRepository } from '@/features/ai/chatbot/services/chatbot-session-repository';
import { contextRegistryConsumerEnvelopeSchema } from '@/shared/contracts/ai-context-registry';
import type { ChatMessageRoleDto } from '@/shared/contracts/chatbot';
import { runChatbotModel } from '@/shared/lib/ai/chatbot/server-model-runtime';
import { resolveBrainModelExecutionConfig } from '@/shared/lib/ai-brain/server';
import { AppError, AppErrorCodes } from '@/shared/errors/app-error';

type ChatPayloadMessage = {
  role: string;
  content: string;
  images?: string[];
};

type ChatPayload = {
  model?: string;
  messages?: ChatPayloadMessage[];
  options?: Record<string, unknown>;
  contextRegistry?: unknown;
};

const DEFAULT_CHATBOT_SYSTEM_PROMPT = 'You are a helpful assistant.';

/**
 * Executes a chatbot job, performing model inference and persisting the results.
 * 
 * @param jobId - Unique identifier of the job to process.
 * @throws AppError if job payload is invalid, the model fails to return a response, or persistence fails.
 */
export const processJob = async (jobId: string): Promise<void> => {
  const job = await chatbotJobRepository.findById(jobId);
  if (!job) {
    throw new AppError(`Chatbot job not found: ${jobId}`, {
        code: AppErrorCodes.notFound,
        httpStatus: 404,
    });
  }
  if (job.status !== 'running') return;

  const payload = job.payload as ChatPayload;
  if (!Array.isArray(payload?.messages) || payload.messages.length === 0) {
    throw new AppError('Chatbot job payload missing or invalid: messages array required.', {
        code: AppErrorCodes.validation,
        httpStatus: 400,
        meta: { jobId, payload },
    });
  }

  const messages = payload.messages.filter(
    (message: ChatPayloadMessage): boolean =>
      typeof message?.role === 'string' && typeof message?.content === 'string'
  );

  if (messages.length !== payload.messages.length) {
    throw new AppError('Chatbot job payload contains malformed messages.', {
        code: AppErrorCodes.validation,
        httpStatus: 400,
        meta: { jobId },
    });
  }

  const brainConfig = await resolveBrainModelExecutionConfig('chatbot', {
    defaultTemperature: 0.7,
    defaultMaxTokens: 800,
    defaultSystemPrompt: DEFAULT_CHATBOT_SYSTEM_PROMPT,
  });

  const parsedContextRegistry = contextRegistryConsumerEnvelopeSchema.safeParse(
    payload.contextRegistry
  );
  const contextRegistryPrompt = parsedContextRegistry.success
    ? buildChatbotContextRegistrySystemPrompt(parsedContextRegistry.data.resolved)
    : '';
  const systemPrompt = [brainConfig.systemPrompt, contextRegistryPrompt].filter(Boolean).join('\n\n');

  try {
    const result = await runChatbotModel({
      messages: messages.map((m) => ({
        ...m,
        role: m.role as ChatMessageRoleDto,
      })),
      modelId: brainConfig.modelId,
      temperature: brainConfig.temperature,
      maxTokens: brainConfig.maxTokens,
      systemPrompt,
    });

    await chatbotSessionRepository.addMessage(job.sessionId, {
      role: 'assistant',
      content: result.message ?? 'No response from model.',
      timestamp: new Date().toISOString(),
      model: brainConfig.modelId,
      metadata: {
        brainApplied: brainConfig.brainApplied,
      },
    });

    await chatbotJobRepository.update(job.id, {
      status: 'completed',
      model: brainConfig.modelId,
      payload: {
        ...job.payload,
        model: brainConfig.modelId,
        options: {
          ...(payload.options ?? {}),
          brainApplied: brainConfig.brainApplied,
        },
      },
      finishedAt: new Date(),
      resultText: (result.message ?? 'No response from model.').slice(0, 2000),
    });
  } catch (error) {
    throw new AppError(`Failed to process chatbot job: ${jobId}`, {
      code: AppErrorCodes.internal,
      httpStatus: 500,
      cause: error,
      meta: { jobId, sessionId: job.sessionId },
    });
  }
};
